      />
      <button type="submit">Add Task</button>
    </form>
  );
}

export default AddTask;
```

**Key Concepts**:
- Local `useState` for input value (controlled component).
- `onSubmit` prevents page reload and calls parent's `onAddTask` if text isn't empty.

