# Minimal Flask app for Notes API (CRUD on in-memory storage)
# Run with: flask --app app run
# Or export FLASK_APP=app.py && flask run

from flask import Flask, request, jsonify
import uuid

app = Flask(__name__)

# In-memory storage: list of notes
notes = []

@app.route('/notes', methods=['GET'])
def get_notes():
    """Retrieve all notes."""
    return jsonify(notes)

@app.route('/notes', methods=['POST'])
def create_note():
    """Create a new note."""
    data = request.get_json()
    if not data or 'content' not in data:
        return jsonify({'error': 'Content is required'}), 400

    note = {
        'id': str(uuid.uuid4()),
        'content': data['content']
    }
    notes.append(note)
    return jsonify(note), 201

@app.route('/notes/<note_id>', methods=['GET'])
def get_note(note_id):
    """Retrieve a specific note."""
    for note in notes:
        if note['id'] == note_id:
            return jsonify(note)
    return jsonify({'error': 'Note not found'}), 404

@app.route('/notes/<note_id>', methods=['PUT'])
def update_note(note_id):
    """Update an existing note."""
    data = request.get_json()
    if not data or 'content' not in data:
        return jsonify({'error': 'Content is required'}), 400

    for i, note in enumerate(notes):
        if note['id'] == note_id:
            notes[i] = {'id': note_id, 'content': data['content']}
            return jsonify(notes[i])
    return jsonify({'error': 'Note not found'}), 404

@app.route('/notes/<note_id>', methods=['DELETE'])
def delete_note(note_id):
    """Delete a note."""
    for i, note in enumerate(notes):
        if note['id'] == note_id:
            notes.pop(i)
            return '', 204
    return jsonify({'error': 'Note not found'}), 404

if __name__ == '__main__':
    app.run(debug=True)

# Usage examples:
# POST /notes - {"content": "Hello world"} -> creates note
# GET /notes -> lists all
# GET /notes/{id} -> single note
# PUT /notes/{id} - {"content": "Updated"} -> updates
# DELETE /notes/{id} -> deletes
